 using Microsoft.ML;
 using Microsoft.ML.Data;
 using Microsoft.Extensions.ML;

 var builder = WebApplication.CreateBuilder(args);

 // Train the model at startup
 var mlContext = new MLContext(seed: 42);
 var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
 var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');

 var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);

 var labelLookup = new[]
 {
     new KeyValuePair<string, bool>("Yes", true),
     new KeyValuePair<string, bool>("No", false)
 };

 var pipeline = mlContext.Transforms.Conversion
         .MapValue("Label", labelLookup, inputColumnName: nameof(CustomerData.Churned))
     .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
     .Append(mlContext.Transforms.Concatenate("Features",
         nameof(CustomerData.Age), nameof(CustomerData.Income),
         "RegionEncoded", nameof(CustomerData.PurchaseHistory)))
     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
         labelColumnName: "Label", featureColumnName: "Features"));

 var model = pipeline.Fit(split.TrainSet);

 // Evaluate — use full dataset when test set is too small for meaningful metrics
 var evalData = model.Transform(split.TestSet);
 long testRowCount = evalData.GetColumn<bool>("PredictedLabel").Count();
 if (testRowCount < 2)
 {
     evalData = model.Transform(dataView);
     Console.WriteLine("⚠ Test set too small — evaluated on training data. Add more rows for a proper split.");
 }
 var metrics = mlContext.BinaryClassification.Evaluate(evalData, labelColumnName: "Label");
 Console.WriteLine($"AUC: {metrics.AreaUnderRocCurve:F4}  F1: {metrics.F1Score:F4}  Accuracy: {metrics.Accuracy:F4}");

 // Save model and register thread-safe pooled prediction engine
 var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "churn-model.zip");
 mlContext.Model.Save(model, dataView.Schema, modelPath);

 builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
     .FromFile(modelPath);

 var app = builder.Build();

 app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

 app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerRequest req) =>
